let b = $json.body;
if (typeof b === 'string') { try { b = JSON.parse(b); } catch (e) { b = {}; } }
b = b || {};
const topic = (b.topic || $json.topic || ($json.query && $json.query.topic) || '隨意寫一則範例貼文').toString();
const prompt = '你是社群內容寫手，擅長反主流框架的爆款貼文。根據主題，為 FB / IG / Threads 各寫一則草稿：反直覺鉤子開頭、第一人稱真實口語、結尾不釣互動、繁體中文全形標點。\n\n主題：\n' + topic;
return [{ json: { topic, prompt } }];

const data = $input.first().json;
let result = '';
try { result = (data.message && data.message.content) || (data.content && data.content[0] && data.content[0].text) || data.response || ''; } catch (e) {}
if (!result) result = JSON.stringify(data);
return [{ json: { result } }];
